UPDATE public.courses SET detail_content = '{"longDescription":"Web Development: questa è un''immersione nel mondo dello sviluppo web. I ragazzi impareranno linguaggi e stili di markup, impareranno a collegare il sito a database, creeranno design e costruiranno il proprio sito web. Il corso copre HTML, CSS, JavaScript, PHP e WordPress.","age":"13+ anni","level":"Principiante","duration":"32 lezioni","tags":["HTML","CSS","Sviluppo web","Programmazione"],"topics":["Creare layout in Figma","Database e motori di siti","Sviluppo di siti web responsive","Imparare HTML per creare markup di siti","Imparare CSS per applicare stili","Lavorare con le animazioni del sito web","Creazione di database per lavorare con gli utenti"],"projectExamples":[{"title":"Portfolio personale"},{"title":"Landing page professionale"},{"title":"Sito web completo con WordPress"}],"modules":[{"title":"Modulo 1. Introduzione a HTML","lessons":["1. Gli studenti impareranno cos''è una pagina HTML e proveranno a creare il loro primo layout usando le etiquette più semplici.","2. Multimedia ed embedding. Gli studenti impareranno a usare etiquette multimedia: img, video, audio.","3. Frame e markup di pagina, apprendimento dell''etiquetta iframe e embedding di elementi.","4. Introduzione a CSS. I ragazzi impareranno le basi di CSS e applicheranno i loro primi stili."],"result":"Nel primo modulo, gli studenti creeranno pagine web integrando contenuti multimedia e apprenderanno le basi della stilizzazione degli elementi."},{"title":"Modulo 2. Concetti base di CSS","lessons":["5. Selettori CSS. Gli studenti impareranno cosa sono i selettori e come impostare stili per elementi specifici.","6. Il modello a blocchi di CSS. Elementi del modello a blocchi e inline, display e proprietà dei blocchi.","7. Link e proprietà di sfondo. Etiquetta <a>, link interni ed esterni, configurazione dello sfondo.","8. Posizionamento. Flusso del documento e posizioni degli elementi, proprietà position."],"result":"Nel secondo modulo, gli studenti padroneggeranno temi fondamentali per ottenere un web design professionale."},{"title":"Modulo 3. Prototipazione e basi di UX/UI","lessons":["9. Introduzione al design. Cos''è il design UX e UI, qual è la loro differenza?","10. Analisi dei motori di ricerca. Studio dei motori di ricerca e del funzionamento di Internet.","11. Mock-up del progetto finale: introduzione a Figma, basi della prototipazione.","12. Flexbox. I ragazzi impareranno la proprietà più importante di CSS: i Flexbox."],"result":"Gli studenti apprenderanno le basi del design di siti web e svilupperanno il design del loro futuro progetto."},{"title":"Modulo 4. Design","lessons":["13. Design del sito web, lavoro con VSC. Conoscenza dell''editor e lavoro sul primo progetto.","14. Completamento del progetto. Finalizzazione e completamento del progetto.","15. Pubblicazione di un progetto. Cos''è GitHub e come pubblicare il tuo sito?","16. Presentazione dei progetti. Riepilogo di quanto fatto nei quattro moduli."],"result":"Gli studenti creeranno il loro primo sito web, lo pubblicheranno online e raccoglieranno feedback dagli utenti."},{"title":"Modulo 5. CSS Avanzato","lessons":["17. Pseudo-classi e pseudo-elementi. Studio di pseudo-classi e pseudo-elementi importanti.","18. Trasformazioni. Esplorazione delle trasformazioni, rendere il sito interattivo.","19. Animazioni. La proprietà animation e come funzionano le animazioni in CSS.","20. Modello a blocchi PRO. Differenza tra margin e padding, applicazione al progetto."],"result":"Gli studenti padroneggeranno CSS avanzato e miglioreranno il loro progetto."},{"title":"Modulo 6. Layout adattivo, grid e form","lessons":["21. Layout Grid. La seconda proprietà importante di CSS. Differenza con i flex.","22. Variabili in CSS. La variabile root che cambierà molto il nostro sito!","23. Design adattivo e responsive. Come rendere un sito adattabile?","24. Interazione con le informazioni dell''utente. Form, come inviare informazioni al server."],"result":"Gli studenti impareranno grid più comode, risolveranno casi reali e apprenderanno a fare adattamenti."},{"title":"Modulo 7. Motori di siti e basi di PHP","lessons":["25. Server locale e introduzione a PHP. Apprendimento di PHP per il sito, interazione con HTML.","26. Immersione in PHP. Apprendimento di cicli e array, come costruire il proprio sito PHP.","27. WordPress. Motori di siti e WordPress, come creare un sito da blocchi PHP.","28. Motore del sito ed estensione del progetto sul motore."],"result":"Gli studenti apprenderanno hosting e PHP, e come trasferire il loro progetto sul server."},{"title":"Modulo 8. Elaborazione del progetto finale","lessons":["29. Elaborazione del progetto finale.","30. Perfezionamento del progetto, lavoro con form, codice pronto per verificare la correttezza dell''input.","31. Perfezionamento del progetto, menu hamburger, carousel, chips JS. Completamento del progetto.","32. Presentazione dei progetti."],"result":"Per tutti i moduli, gli studenti lavoreranno al miglioramento del loro progetto, creando un buon prodotto finale."}]}'::jsonb WHERE slug = 'web-development' AND (detail_content IS NULL OR detail_content = '{}'::jsonb);

UPDATE public.courses SET detail_content = '{"longDescription":"Durante questo corso, gli studenti (dai 13 ai 17 anni) impareranno Unity, uno dei motori più popolari nel settore dei giochi. Gli studenti padroneggeranno il motore in grado di consentire loro di creare giochi, animazioni e progetti software unici e coinvolgenti. Durante il corso, gli studenti impareranno C#, il linguaggio di programmazione che consentirà loro di creare funzioni complesse. Alla fine del corso, gli studenti creeranno i propri giochi 3D che potranno essere giocati sia su PC che su browser web.","age":"13+ anni","level":"Principiante","duration":"32 lezioni","tags":["Programmazione","3D","C#","Game Engines","Sviluppo di giochi"],"topics":["Introduzione al linguaggio C#","Fondamenti di sviluppo di giochi sparatutto e fondamenti di intelligenza artificiale","Fondamenti di sviluppo di giochi multiplayer","Utilizzo di GitHub","Sviluppo del tuo primo Unity FPS (sparatutto in prima persona)","Progettazione e implementazione giochi multiplayer"],"projectExamples":[{"title":"Runner Game"},{"title":"Sparatutto FPS"},{"title":"Gioco Multiplayer"}],"modules":[{"title":"M1. Sviluppare un gioco Runner - Introduzione a Unity e C#","lessons":["1. Finestre di Unity. Creazione di personaggi e luoghi.","2. Introduzione alla programmazione in C#. Configura la fisica del movimento per il giocatore.","3. Imparare l''istruzione condizionale if/else. Insegnare al nostro personaggio a saltare.","4. Scoprire di più sulla telecamera del gioco. Animare il movimento del personaggio."],"result":"Gli studenti hanno iniziato a sviluppare il loro primo gioco Unity creando personaggi e luoghi. Hanno imparato le basi del linguaggio C#."},{"title":"M2. Sviluppare un gioco Runner - Creazione di livelli e basi dell''UI","lessons":["5. Conoscere gli elenchi C# e la funzione Istance. Costruire un generatore di livelli base.","6. Conoscere il ciclo for C#. Implementare il livellamento continuo.","7. Apprendimento delle basi dell''UI (User Interface). Aggiungi oggetti da collezione e lost status.","8. Unificazione delle basi di C#. Familiarizzare con effetti e suoni. Aggiungi bonus."],"result":"Gli studenti hanno completato il loro primo gioco di corsa e lo hanno pubblicato su Kodland HUB."},{"title":"M3. Sviluppare uno sparatutto - Fondamenti FPS e IA","lessons":["9. Creazione di un nuovo progetto. Implementazione dei controlli dei personaggi in prima persona.","10. Creare modelli e animazioni per i nemici. Implementazione di un''intelligenza artificiale primitiva.","11. Aggiunta di armi e meccaniche di tiro di base. Implementazione del conteggio delle munizioni.","12. Fondamenti di game design. Implementazione di checkpoint e respawn."],"result":"Gli studenti hanno iniziato a sviluppare il loro primo Unity FPS con nemici e IA semplice."},{"title":"M4. Sviluppare uno sparatutto - Introduzione alla OOP","lessons":["13. Introduzione all''OOP (programmazione orientata agli oggetti). Principi base, classi e oggetti.","14. OOP avanzato. Utilizzo del polimorfismo per sovrascrivere i metodi della superclasse.","15. Utilizzo dei concetti OOP per implementare diverse classi di personaggi con abilità uniche.","16. Completare il gioco sparatutto. Aggiunta di suoni ed effetti visivi, lavoro sul menu."],"result":"Gli studenti hanno imparato le basi dell''OOP e pubblicato i loro progetti su Itch.io."},{"title":"M5. Sviluppo di uno sparatutto multiplayer - Fondamenti multiplayer","lessons":["17. Introduzione allo sviluppo di giochi multiplayer. Introduzione a Photon.","18. Connessione al servizio Photon. Crea e unisciti a stanze virtuali.","19. Utilizzo delle funzioni Photon per sincronizzare le azioni e gli stati dei giocatori.","20. Apprendimento delle funzionalità avanzate di Photon per migliorare la sincronizzazione."],"result":"Gli studenti hanno strutturato i loro progetti per la funzionalità multiplayer con Photon."},{"title":"M6. Sviluppo di uno sparatutto multiplayer - Funzionalità avanzate","lessons":["21. Realizzazione di varie funzionalità di gioco in ambiente multiplayer: IA nemica, bonus, punteggio.","22. Ottimizzare il gioco. Ottimizzazione dei suoni, dell''interfaccia e delle prestazioni.","23. Implementare funzionalità multiplayer avanzate: matchmaking, lobby e gestione dati runtime.","24. Guardare il gioco in streaming e giocare insieme."],"result":"Gli studenti hanno completato il loro gioco sparatutto multiplayer e lo hanno pubblicato su Itch.io."},{"title":"M7. Inizio del lavoro per il progetto finale","lessons":["25. Fondamenti di game design. Progettare un documento concettuale per un gioco.","26. Comprendere il controllo della versione. Imparare GitHub.","27. Progettazione dei livelli. Lavoro sulla grafica dei propri giochi.","28. Pubblicazione e test delle versioni beta dei propri giochi."],"result":"Gli studenti hanno iniziato a progettare i loro progetti finali e imparato a lavorare con GitHub."},{"title":"M8. Completamento del progetto finale - Diploma","lessons":["29. Insegnare al giocatore. Sviluppo di un''interfaccia user-friendly.","30. Pubblicare progetti su Itch.io.","31. Percorso evolutivo: dare gli ultimi ritocchi prima della presentazione.","32. Presentazione dei progetti. Diploma di fine corso."],"result":"Gli studenti hanno creato i propri giochi con design e storie originali e li hanno pubblicati su Itch.io."}]}'::jsonb WHERE slug = 'unity' AND (detail_content IS NULL OR detail_content = '{}'::jsonb);
